form:Form.form:Scripts:
		var MyOBJ;
var MyHOR;
var MyHORSEL="";
var ETimeStart=0;


function ObtenerTiposHoras()
{ 
var proxy;
var TIPOSHORA;
var retval;
var t;

proxy=new NomadProxy();
TIPOSHORA=proxy.SQLService().GetOBJ(Ctrl("main").getResource("TIPOS_DE_HORAS"),"");

retval=new Array();
if (Ctrl("main").GetMode()=="EDIT" || Ctrl("main").GetMode()=="DEBUG")
{
	retval[""]=new Object();
	retval[""].id   ="";
	retval[""].label="Eliminar";
	retval[""].color="";
}

for (t=0; t<TIPOSHORA.Child.length; t++)
	retval[TIPOSHORA.Child[t].id.toString()]=TIPOSHORA.Child[t];

return retval;
}

function DrawReference(arr, ContainerName, KeySelect)
{                         
var HTMLoutput="", key;
var TrgObj=document.getElementById(ContainerName);

HTMLoutput+="<TABLE style='width:100%;height:100%cursor:default;font-family:arial;font-size:10px;font-weight:bold;color:#000000;background-color:#F0F0D0;' >";
for (key in arr)
{      

	if (arr[key].color=="")
		HTMLoutput+="<TR style='height:20px;"+(key==KeySelect?"background-color:#F0F0A0;":"")+"' >"
		           +"<TD onclick='SetHorario(\""+key+"\");' style='border-bottom:1px dotted #808080;' ><img src='../images/HelperPage/cancel_n.gif' /></TD>"
		           +"<TD onclick='SetHorario(\""+key+"\");' style='border-bottom:1px dotted #808080;' >"+arr[key].label+"</TD>"
		           +"</TR>";
	else
		HTMLoutput+="<TR style='height:20px;"+(key==KeySelect?"background-color:#F0F0A0;":"")+"' >"
		           +"<TD onclick='SetHorario(\""+key+"\");' style='border-bottom:1px dotted #808080;width:30px;font-size:1px;' ><div style='padding:0px;height:12px;border-left:2px solid #"+arr[key].color+";border-right:2px solid #"+arr[key].color+";' ><div style='position:relative;top:4px;height:4px;width:100%;background-color:#"+arr[key].color+";' ></div></div></TD>"
		           +"<TD onclick='SetHorario(\""+key+"\");' style='border-bottom:1px dotted #808080;' >"+arr[key].label+"</TD>"
		           +"</TR>";
}
HTMLoutput+="</TABLE>";

TrgObj.innerHTML=HTMLoutput;
}      

function SetHorario(myId)
{
if (Ctrl("main").GetMode()!="EDIT" && Ctrl("main").GetMode()!="DEBUG") return;

MyHORSEL=myId;
DrawReference(MyHOR, "CONT_REFER", MyHORSEL);

if (MyHORSEL=="")
	MyOBJ.SelectStyle("000000","BAR");
else
	MyOBJ.SelectStyle(MyHOR[MyHORSEL].color,"TIME");

}  

function CalculateMinMax()
{ 
var min=2960, max=-1300, MyHORS, d, MyNewHORS, pos, he, hs;
var DAY="NRM|DOM|FER|DYF|NOL".split("|");

for (var d=0; d<5; d++)
{
	MyHORS=Ctrl(DAY[d]).GetXValue();
	if (MyHORS=="") continue;

	MyNewHORS=MyHORS.split("|");

 	pos=1;
	while (pos<MyNewHORS.length) 
	{                                 
	  if (MyNewHORS[pos]!="")
	  {
			he=parseInt(MyNewHORS[pos-1],10);
			hs=parseInt(MyNewHORS[pos+1],10);

			if (he<min) min=he;
			if (he>max) max=he;
			if (hs<min) min=hs;
			if (hs>max) max=hs;
		}

		pos+=2;
	}
}      

retval=new Object();
retval.Min=min;
retval.Max=max;   

return retval; 
}

function MoveLeft()
{
if (ETimeStart<=-23) return;

var obj=CalculateMinMax();
if (obj.Max>(24+ETimeStart-1)*60) return;

ETimeStart--;
MyOBJ.SetAxisTime(ETimeStart*60, (25+ETimeStart)*60 , 60, 10, 3);
MyOBJ.Draw();
}

function MoveRight()
{                   
if (ETimeStart>= 23) return;

var obj=CalculateMinMax();
if (obj.Min<(ETimeStart+1)*60) return;


ETimeStart++;
MyOBJ.SetAxisTime(ETimeStart*60, (25+ETimeStart)*60 , 60, 10, 3);
MyOBJ.Draw();
}

function Initialize()
{
var e_min=1440*2, e_max=-1440;

MyOBJ=HTMLTimeBarSelected("CONT_TURNO","",AddTurno,null);

MyOBJ.SetAxisMode("SERIE/TIME");
MyOBJ.SetAxisTime(ETimeStart*60, (25+ETimeStart)*60 , 60, 10, 3);

MyOBJ.AddSerie("NRM","Habil");
MyOBJ.AddSerie("DOM","Domingo");
MyOBJ.AddSerie("FER","Feriado");
MyOBJ.AddSerie("DYF","Dom+Fer");
MyOBJ.AddSerie("NOL","No Laborable");

MyOBJ.Draw();               

if (Ctrl("main").GetMode()=="EDIT" || Ctrl("main").GetMode()=="DEBUG") 
{
	MyOBJ.EditStart();           
	MyOBJ.SelectStyle("000000","BAR");
}


MyHOR=ObtenerTiposHoras();
DrawReference(MyHOR, "CONT_REFER", MyHORSEL);

if (Ctrl("main").GetMode()=="DEBUG") 
	str=Ctrl("main").getResource("DEBUG");
else
	str=DOM2String(Ctrl("main").GetLastDoc("RS"));

var X=new nomadDOM(str);

for (var t=0; t<X.Child.length; t++)
{    
	if (X.Child[t]["nmd-status"])
	{                  
		if (X.Child[t]["nmd-status"].substr(0,3)=="~d,") continue;
		if (X.Child[t]["nmd-status"].substr(0,3)=="~x,") continue;
	}				

	if (parseInt(X.Child[t].e_hora_inicio)<parseInt(e_min)) e_min=X.Child[t].e_hora_inicio;		
	if (parseInt(X.Child[t].e_hora_inicio)>parseInt(e_max)) e_max=X.Child[t].e_hora_inicio;
	if (parseInt(X.Child[t].e_hora_fin)   <parseInt(e_min)) e_min=X.Child[t].e_hora_fin;
	if (parseInt(X.Child[t].e_hora_fin)   >parseInt(e_max)) e_max=X.Child[t].e_hora_fin;

	AddTurnoString("NRM", X.Child[t].e_hora_inicio, X.Child[t].e_hora_fin, X.Child[t].oi_tipo_hs_norm.value);
	AddTurnoString("DOM", X.Child[t].e_hora_inicio, X.Child[t].e_hora_fin, X.Child[t].oi_tipo_hs_dom.value);
	AddTurnoString("FER", X.Child[t].e_hora_inicio, X.Child[t].e_hora_fin, X.Child[t].oi_tipo_hs_fer.value);
	AddTurnoString("DYF", X.Child[t].e_hora_inicio, X.Child[t].e_hora_fin, X.Child[t].oi_tipo_hs_domfer.value);
	AddTurnoString("NOL", X.Child[t].e_hora_inicio, X.Child[t].e_hora_fin, X.Child[t].oi_tipo_hs_nolab.value);

} 

DrawTurno(MyOBJ, "NRM");
DrawTurno(MyOBJ, "DOM");
DrawTurno(MyOBJ, "FER");
DrawTurno(MyOBJ, "DYF");   
DrawTurno(MyOBJ, "NOL");

while (e_min<ETimeStart*60) ETimeStart--;
while (e_max>(24+ETimeStart)*60) ETimeStart++;

MyOBJ.SetAxisTime(ETimeStart*60, (25+ETimeStart)*60 , 60, 10, 3);
MyOBJ.Draw();
}

function DrawTurno(obj, fecha)
{  
var MyHORS, MyNewHORS;

//Simplifico	
MyNewHORS=new Array();
MyHORS=Ctrl(fecha).GetXValue();
if (MyHORS=="") MyHORS=(-24*60)+"||"+(1440+24*60);
MyHORS=MyHORS.split("|");

 	pos=0;
while (pos<MyHORS.length) 
{                     
	if ((pos==0) || (MyHORS.length==pos+1) || (MyHORS[pos+1]!=MyNewHORS[MyNewHORS.length-1]))
	{
		MyNewHORS[MyNewHORS.length]=MyHORS[pos];
		if (pos+1<MyHORS.length) MyNewHORS[MyNewHORS.length]=MyHORS[pos+1];
	}
	pos+=2;
}
Ctrl(fecha).SetXValue(MyNewHORS.join("|"));

//Limpio
obj.ClearValue(fecha);

//Agrego los Horarios	
 	pos=1;
while (pos<MyNewHORS.length) 
{     
	he=parseInt(MyNewHORS[pos-1],10)
	hs=parseInt(MyNewHORS[pos+1],10)
	MyHorID=MyNewHORS[pos];         
	MyHOR2=MyHOR[MyHorID];

	if (MyHorID!="")      
	{     
		if (MyHOR2)
			obj.SetValue(fecha,he,hs,MyHOR[MyHorID].label,MyHOR[MyHorID].color,MyHOR[MyHorID].color,MyHOR[MyHorID].label+" desde "+int2time(he)+" a "+int2time(hs));
		else
			obj.SetValue(fecha,he,hs,"Desconocido","000000","000000","Desconocido desde "+int2time(he)+" a "+int2time(hs));
	}
	pos+=2;
}

//Dibujo                  
obj.ReDraw(fecha);
}

function AddTurnoString(fecha, he, hs, tipo)
{
var  MyHORS, MyNewHORS;            

if (he==hs) return;      

MyNewHORS=new Array();
MyHORS=Ctrl(fecha).GetXValue();
if (MyHORS=="") MyHORS=(-24*60)+"||"+(1440+24*60);
MyHORS=MyHORS.split("|");

pos=0;

//Pego todos los anteriores a la hora de Inicio		                        
while ( parseInt(MyHORS[pos],10)<he && pos<MyHORS.length) 
{
	MyNewHORS[MyNewHORS.length]=MyHORS[pos];
	if (pos+1<MyHORS.length) MyNewHORS[MyNewHORS.length]=MyHORS[pos+1];

	pos+=2;
}       

//Pego el Inicio
MyNewHORS[MyNewHORS.length]=he.toString();
MyNewHORS[MyNewHORS.length]=tipo;

//Ignoro todos los horarios menores de HS
while ( parseInt(MyHORS[pos],10)<=hs && pos<MyHORS.length) 
	pos+=2;                       

//Pego el Final
MyNewHORS[MyNewHORS.length]=hs.toString();
if (pos<MyHORS.length) MyNewHORS[MyNewHORS.length]=MyHORS[pos-1];

//Pego todos los HORARIOS que sobran		                        
while (pos<MyHORS.length) 
{
	MyNewHORS[MyNewHORS.length]=MyHORS[pos];
	if (pos+1<MyHORS.length) MyNewHORS[MyNewHORS.length]=MyHORS[pos+1];
	pos+=2;
}       

Ctrl(fecha).SetXValue(MyNewHORS.join("|"));
}


function AddTurno(obj, fecha, he, hs)
{
//Agregar Turno
AddTurnoString(fecha, he, hs, MyHORSEL);

//Dibujo el Turno
if (obj!=null) DrawTurno(obj, fecha);
}         


function CombinarTurno(he, hs, fecid, tipo)
{
var MyHORS, MyNewHORS, MyArrHor, pos;

MyNewHORS=new Array();
MyHORS=Ctrl("RES").GetXValue();
if (MyHORS=="") MyHORS=(-24*60)+"|,,,,|"+(1440+24*60);
MyHORS=MyHORS.split("|");

pos=0;

//Pego todos los anteriores a la hora de Inicio		                        
while ( parseInt(MyHORS[pos],10)<he && pos<MyHORS.length) 
{
	MyNewHORS[MyNewHORS.length]=MyHORS[pos];
	if (pos+1<MyHORS.length) MyNewHORS[MyNewHORS.length]=MyHORS[pos+1];

	pos+=2;
}                        

if (parseInt(MyHORS[pos],10)!=he)
{
	//Pego el Inicio
	MyNewHORS[MyNewHORS.length]=he.toString();

	//Modifico la Hora
	MyArrHor=(pos==0?new Array(5):MyHORS[pos-1].split(","));
	MyArrHor[fecid]=tipo;
	MyNewHORS[MyNewHORS.length]=MyArrHor.join(",");
} 

//Pego todos los que son internos
while ( parseInt(MyHORS[pos],10)<hs && pos<MyHORS.length) 
{
	MyNewHORS[MyNewHORS.length]=MyHORS[pos];
	if (pos+1<MyHORS.length) 
	{
		//Modifico la Hora
		MyArrHor=MyHORS[pos+1].split(",");
		MyArrHor[fecid]=tipo;
		MyNewHORS[MyNewHORS.length]=MyArrHor.join(",");
	}

	pos+=2;
}

//Ignoro todos los horarios menores de HS
while ( parseInt(MyHORS[pos],10)<=hs && pos<MyHORS.length) 
	pos+=2;                       

//Pego el Final
MyNewHORS[MyNewHORS.length]=hs.toString();
if (pos<MyHORS.length) MyNewHORS[MyNewHORS.length]=MyHORS[pos-1];


//Pego todos los HORARIOS que sobran		                        
while (pos<MyHORS.length) 
{
	MyNewHORS[MyNewHORS.length]=MyHORS[pos];
	if (pos+1<MyHORS.length) MyNewHORS[MyNewHORS.length]=MyHORS[pos+1];
	pos+=2;
}

Ctrl("RES").SetXValue(MyNewHORS.join("|"));
}


function CheckDef(MyCTRL)
{                 
var first, last;
var t, d, id, pos, MyDeff, retval=true;
var DAY="NRM|DOM|FER|DYF|NOL".split("|");

MyDeff=new Array(888);
for (t=0; t<MyDeff.length; t++) MyDeff[t]=0;


last =-1440;
first= 1440;

//Agrego los Horarios
Ctrl("RES").SetXValue("");
for (d=0; d<5; d++)
{
	id=Math.pow(2,d);
	MyHORS=Ctrl(DAY[d]).GetXValue();
	if (MyHORS=="") MyHORS=(-24*60)+"||"+(1440+24*60);
	MyNewHORS=MyHORS.split("|");

 	pos=1;
	while (pos<MyNewHORS.length) 
	{     
		he=(parseInt(MyNewHORS[pos-1],10)-(-24*60))/5;
		hs=(parseInt(MyNewHORS[pos+1],10)-(-24*60))/5;
		MyHorID=MyNewHORS[pos];         

		if (MyHorID!="")
			for(t=he; t<hs; t++)
			{
				MyDeff[t]|=id;
				if (t>last) last=t;
				if (t<first) first=t;
			}

		CombinarTurno(parseInt(MyNewHORS[pos-1],10),parseInt(MyNewHORS[pos+1],10),d,MyHorID);
		pos+=2;
	}
} 
if (last-first >= 288)
{
	MyCTRL.SetError("La definicion del turno no puede superar las 24hs");
	return false;
}

for (d=0; d<5; d++)
{
	id=Math.pow(2,d);
	DrawTurno(MyOBJ, DAY[d]);

	for (t=0; t<MyDeff.length; t++)
		if (((MyDeff[t] & id) ==0) && (MyDeff[t]!=0))
		{
			MyOBJ.SetValue(
				DAY[d],
				(-24*60)+t*5,
				(-24*60)+(t+1)*5,
				"SIN DEFINIR",
				"C00000",
				"C00000",
				"Horario SIN DEFINIR"
			);

			retval=false;
		}

	MyOBJ.ReDraw(DAY[d]);
}

if (!retval) MyCTRL.SetError("Existen rangos sin especificar");
return retval;
}

function ABMTiposHora()
{
openNewFlowWait(
	"NucleusRH.Base.Tiempos_Trabajados.Tipos_Horas.flow",
	"initialize",
	"",
	new ObjTipoHora(),
	"L"
);
}

function ShowTipoHora()
{
if (MyHORSEL=="") return;
openNewFlowWait(
	"NucleusRH.Base.Tiempos_Trabajados.Tipos_Horas.flow",
	"SHOW",
	"<ROWS><ROW id=\""+MyHORSEL+"\" /></ROWS>",
	new ObjTipoHora(),
	"L"
);
}

function ObjTipoHora()
{                 
this.processResult=function(xmlstring)
{
	//Horarios	
	MyHORSEL="";   
	MyHOR=ObtenerTiposHoras();
	DrawReference(MyHOR, "CONT_REFER", MyHORSEL);
}
}
